'use strict';

// CSV line parser. See docs/rows.md for the contract and docs/conventions.md
// for the field rules (quoted fields unwrapped, embedded commas preserved,
// "" unescaped to ", no trimming).
//
// Returns an array of decoded field strings. Pure: no mutation, no I/O.
function parseCsvLine(line) {
  if (line.length === 0) return [''];

  const fields = [];
  let i = 0;

  while (i < line.length) {
    if (line[i] === '"') {
      let field = '';
      i++; // skip opening quote
      while (i < line.length) {
        if (line[i] === '"') {
          if (line[i + 1] === '"') {
            field += '"';
            i += 2;
          } else {
            i++; // skip closing quote
            break;
          }
        } else {
          field += line[i];
          i++;
        }
      }
      fields.push(field);
      if (i < line.length && line[i] === ',') i++;
    } else {
      const start = i;
      while (i < line.length && line[i] !== ',') i++;
      fields.push(line.slice(start, i));
      if (i < line.length) i++; // skip comma
    }
  }

  // A trailing comma means there is one more (empty) field after it.
  if (line[line.length - 1] === ',') fields.push('');

  return fields;
}

module.exports = { parseCsvLine };
